const HOP_RAR: u32 = 0x3512_5801;
const END_RAR: u32 = 0x3512_5802;
const HOP_AAR: u32 = 0x3512_6501;
const END_AAR: u32 = 0x3512_6502;
const HOP_FAILOVER: u32 = 0x3512_65f1;
const CONNECTION_A: SwmDiameterConnectionToken = SwmDiameterConnectionToken::new(NonZeroU64::MIN);
const CONNECTION_B: SwmDiameterConnectionToken = SwmDiameterConnectionToken::new(
    NonZeroU64::new(2).expect("two is a nonzero connection generation"),
);
const SESSION: &str = "session;private;authorization-351";
const USER: &str = "subscriber-private@example.invalid";
const UNKNOWN: u32 = 93_510;

fn avp(code: AvpCode, flags: u8, value: &[u8]) -> Vec<u8> {
    let length = 8 + value.len();
    let mut wire = Vec::with_capacity((length + 3) & !3);
    wire.extend_from_slice(&code.get().to_be_bytes());
    wire.push(flags);
    wire.extend_from_slice(&(length as u32).to_be_bytes()[1..]);
    wire.extend_from_slice(value);
    wire.resize((length + 3) & !3, 0);
    wire
}

fn vendor_avp(code: AvpCode, flags: u8, value: &[u8]) -> Vec<u8> {
    let length = 12 + value.len();
    let mut wire = Vec::with_capacity((length + 3) & !3);
    wire.extend_from_slice(&code.get().to_be_bytes());
    wire.push(flags | 0x80);
    wire.extend_from_slice(&(length as u32).to_be_bytes()[1..]);
    wire.extend_from_slice(&VENDOR_ID_3GPP.get().to_be_bytes());
    wire.extend_from_slice(value);
    wire.resize((length + 3) & !3, 0);
    wire
}

fn message(
    command: u32,
    flags: u8,
    hop: u32,
    end: u32,
    avps: impl IntoIterator<Item = Vec<u8>>,
) -> Vec<u8> {
    let body: Vec<u8> = avps.into_iter().flatten().collect();
    let length = DIAMETER_HEADER_LEN + body.len();
    let mut wire = Vec::with_capacity(length);
    wire.push(1);
    wire.extend_from_slice(&(length as u32).to_be_bytes()[1..]);
    wire.push(flags);
    wire.extend_from_slice(&command.to_be_bytes()[1..]);
    wire.extend_from_slice(&swm::APPLICATION_ID.get().to_be_bytes());
    wire.extend_from_slice(&hop.to_be_bytes());
    wire.extend_from_slice(&end.to_be_bytes());
    wire.extend_from_slice(&body);
    wire
}

fn proxy_info() -> Vec<u8> {
    let children: Vec<u8> = [
        avp(base::AVP_PROXY_HOST, 0x40, b"proxy.private.invalid"),
        avp(base::AVP_PROXY_STATE, 0x40, b"opaque-private-state"),
    ]
    .into_iter()
    .flatten()
    .collect();
    avp(base::AVP_PROXY_INFO, 0x40, &children)
}

