#[derive(Debug, Clone, Copy)]
enum AuthorizationFixture {
    Rar,
    Raa,
    Aar,
    Aaa,
}

const AUTHORIZATION_FIXTURES: [AuthorizationFixture; 4] = [
    AuthorizationFixture::Rar,
    AuthorizationFixture::Raa,
    AuthorizationFixture::Aar,
    AuthorizationFixture::Aaa,
];

impl AuthorizationFixture {
    const fn label(self) -> &'static str {
        match self {
            Self::Rar => "RAR",
            Self::Raa => "RAA",
            Self::Aar => "AAR",
            Self::Aaa => "AAA",
        }
    }

    const fn command(self) -> u32 {
        match self {
            Self::Rar | Self::Raa => 258,
            Self::Aar | Self::Aaa => 265,
        }
    }

    const fn flags(self) -> u8 {
        match self {
            Self::Rar | Self::Aar => 0xc0,
            Self::Raa | Self::Aaa => 0x40,
        }
    }

    const fn identifiers(self) -> (u32, u32) {
        match self {
            Self::Rar | Self::Raa => (HOP_RAR, END_RAR),
            Self::Aar | Self::Aaa => (HOP_AAR, END_AAR),
        }
    }

    fn avps(self) -> Vec<Vec<u8>> {
        match self {
            Self::Rar => rar_avps(),
            Self::Raa => raa_avps(),
            Self::Aar => aar_avps(),
            Self::Aaa => aaa_avps(),
        }
    }

    fn wire(self, avps: Vec<Vec<u8>>) -> Vec<u8> {
        let (hop, end) = self.identifiers();
        message(self.command(), self.flags(), hop, end, avps)
    }

    fn parse(self, wire: &[u8], ctx: DecodeContext) -> Result<(), DecodeError> {
        let message = decode(wire);
        match self {
            Self::Rar => swm::parse_swm_re_auth_request(&message, ctx).map(|_| ()),
            Self::Raa => swm::parse_swm_re_auth_answer(&message, ctx).map(|_| ()),
            Self::Aar => swm::parse_swm_authorization_request(&message, ctx).map(|_| ()),
            Self::Aaa => swm::parse_swm_authorization_answer(&message, ctx).map(|_| ()),
        }
    }
}

fn avp_code(raw: &[u8]) -> u32 {
    u32::from_be_bytes(raw[0..4].try_into().expect("fixture AVP has a code"))
}

fn replace_first_avp(avps: &mut [Vec<u8>], code: AvpCode, replacement: Vec<u8>) {
    let entry = avps
        .iter_mut()
        .find(|raw| avp_code(raw) == code.get())
        .expect("fixture contains the AVP being mutated");
    *entry = replacement;
}

fn assert_bounded_rejection(
    fixture: AuthorizationFixture,
    class: &str,
    wire: &[u8],
    ctx: DecodeContext,
) -> DecodeError {
    let error = match fixture.parse(wire, ctx) {
        Ok(()) => panic!("{} must reject {class}", fixture.label()),
        Err(error) => error,
    };
    assert!(
        error.offset() <= wire.len(),
        "{} {class} offset {} exceeds wire length {}",
        fixture.label(),
        error.offset(),
        wire.len()
    );
    error
}

fn decode(wire: &[u8]) -> Message<'_> {
    let (tail, message) = Message::decode(wire, DecodeContext::default())
        .expect("hand-authored Diameter fixture must frame");
    assert!(tail.is_empty());
    message
}

fn encode(message: &OwnedMessage) -> Vec<u8> {
    let mut wire = BytesMut::new();
    message
        .encode(&mut wire, EncodeContext::default())
        .expect("typed message must encode");
    wire.to_vec()
}

fn expected_re_auth_peer(connection: SwmDiameterConnectionToken) -> SwmExpectedAnswerPeer {
    SwmExpectedAnswerPeer::direct(connection, "epdg.private.invalid", "access.private.invalid")
}

fn expected_authorization_peer(connection: SwmDiameterConnectionToken) -> SwmExpectedAnswerPeer {
    SwmExpectedAnswerPeer::routed(connection)
}

fn parsed_re_auth_request(wire: &[u8]) -> SwmReAuthRequestEnvelope {
    swm::parse_swm_re_auth_request_envelope(&decode(wire), DecodeContext::default())
        .expect("valid RAR must parse")
        .with_expected_answer_peer(expected_re_auth_peer(CONNECTION_A))
}

fn parsed_authorization_request(wire: &[u8]) -> swm::SwmAuthorizationRequestEnvelope {
    swm::parse_swm_authorization_request_envelope(&decode(wire), DecodeContext::default())
        .expect("valid AAR must parse")
        .with_expected_answer_peer(expected_authorization_peer(CONNECTION_A))
}

fn parsed_re_auth_answer(
    message: &Message<'_>,
    connection: SwmDiameterConnectionToken,
) -> swm::SwmReAuthAnswerEnvelope {
    swm::parse_swm_re_auth_answer_envelope_from_connection(
        message,
        connection,
        DecodeContext::default(),
    )
    .expect("valid RAA must parse")
}

fn parsed_authorization_answer(
    message: &Message<'_>,
    connection: SwmDiameterConnectionToken,
) -> swm::SwmAuthorizationAnswerEnvelope {
    swm::parse_swm_authorization_answer_envelope_from_connection(
        message,
        connection,
        DecodeContext::default(),
    )
    .expect("valid AAA must parse")
}

#[test]
fn rar_fixture_round_trips_and_retains_t() {
    for flags in [0xc0, 0xd0] {
        let wire = rar_wire(flags);
        let envelope = parsed_re_auth_request(&wire);
        assert_eq!(envelope.request().session_id.as_ref(), SESSION);
        assert_eq!(envelope.request().user_name.as_ref(), USER);
        assert_eq!(
            envelope.request().re_auth_request_type,
            SwmReAuthRequestType::AuthorizeOnly
        );
        assert_eq!(envelope.proxy_info_count(), 1);
        assert_eq!(envelope.is_potentially_retransmitted(), flags & 0x10 != 0);
        let rebuilt = swm::build_swm_re_auth_request(&envelope, EncodeContext::default())
            .expect("parsed RAR must rebuild");
        assert_eq!(encode(&rebuilt), wire);
    }
}

#[test]
fn raa_fixture_round_trips_and_correlates() {
    let request = parsed_re_auth_request(&rar_wire(0xc0));
    let answer_wire = raa_wire();
    let answer = parsed_re_auth_answer(&decode(&answer_wire), CONNECTION_A);
    assert_eq!(answer.answer().result, SwmReAuthResult::Success);
    let rebuilt =
        swm::build_swm_re_auth_answer(&request, answer.answer(), EncodeContext::default())
            .expect("parsed RAA must rebuild");
    assert_eq!(encode(&rebuilt), answer_wire);
    request
        .correlate_answer(answer)
        .expect("exact RAR/RAA must correlate");
}

#[test]
fn correlation_rejects_a_changed_proxy_chain() {
    let request = parsed_re_auth_request(&rar_wire(0xc0));
    let mut answer_avps = vec![
        avp(base::AVP_SESSION_ID, 0x40, SESSION.as_bytes()),
        avp(
            base::AVP_RESULT_CODE,
            0x40,
            &base::RESULT_CODE_DIAMETER_SUCCESS.to_be_bytes(),
        ),
        avp(base::AVP_ORIGIN_HOST, 0x40, b"epdg.private.invalid"),
        avp(base::AVP_ORIGIN_REALM, 0x40, b"access.private.invalid"),
        avp(base::AVP_USER_NAME, 0x40, USER.as_bytes()),
    ];
    let changed_children: Vec<u8> = [
        avp(base::AVP_PROXY_HOST, 0x40, b"proxy.private.invalid"),
        avp(base::AVP_PROXY_STATE, 0x40, b"changed-private-state"),
    ]
    .into_iter()
    .flatten()
    .collect();
    answer_avps.push(avp(base::AVP_PROXY_INFO, 0x40, &changed_children));
    let wire = message(258, 0x40, HOP_RAR, END_RAR, answer_avps);
    let answer = parsed_re_auth_answer(&decode(&wire), CONNECTION_A);
    let error = request
        .correlate_answer(answer)
        .expect_err("changed Proxy-State must not correlate");
    assert_eq!(error.as_str(), "swm_authorization_proxy_info_mismatch");
}

#[test]
fn aar_fixture_round_trips_with_typed_vendor_values() {
    let wire = aar_wire(0xc0);
    let envelope = parsed_authorization_request(&wire);
    let request = envelope.request();
    assert_eq!(request.auth_request_type, AuthRequestType::AuthorizeOnly);
    assert_eq!(
        request.aar_flags,
        Some(SwmAarFlags::wlan_location_info_request())
    );
    assert_eq!(
        request.ue_local_ip_address,
        Some(IpAddr::V4(Ipv4Addr::new(198, 51, 100, 10)))
    );
    assert_eq!(
        request.high_priority_access_info,
        Some(SwmHighPriorityAccessInfo::configured())
    );
    let rebuilt = swm::build_swm_authorization_request(&envelope, EncodeContext::default())
        .expect("parsed AAR must rebuild canonically");
    let rebuilt_wire = encode(&rebuilt);
    assert_eq!(rebuilt_wire[4] & 0x10, 0);
    assert_ne!(
        rebuilt_wire, wire,
        "undefined vendor flag bits are canonicalized"
    );
    let mut retry = envelope.clone();
    retry.mark_for_failover_retransmission(HOP_FAILOVER, expected_authorization_peer(CONNECTION_B));
    let retry_wire = encode(
        &swm::build_swm_authorization_request(&retry, EncodeContext::default())
            .expect("AAR retry must build"),
    );
    assert_eq!(retry_wire[4] & 0x10, 0x10);
    assert_eq!(&retry_wire[5..12], &rebuilt_wire[5..12]);
    assert_eq!(&retry_wire[16..], &rebuilt_wire[16..]);
    assert_eq!(&retry_wire[12..16], &HOP_FAILOVER.to_be_bytes());
}

#[test]
fn understood_table_avps_ignore_received_m_mismatch_and_encode_canonically() {
    let mut avps = aar_avps();
    for raw in &mut avps {
        let code = u32::from_be_bytes(raw[0..4].try_into().expect("fixed AVP code"));
        if code == swm::AVP_AAR_FLAGS.get()
            || code == swm::AVP_UE_LOCAL_IP_ADDRESS.get()
            || code == swm::AVP_HIGH_PRIORITY_ACCESS_INFO.get()
        {
            raw[4] |= 0x40;
        }
    }
    avps.insert(1, avp(swm::AVP_DRMP, 0x40, &3_u32.to_be_bytes()));
    let wire = message(265, 0xc0, HOP_AAR, END_AAR, avps);
    let envelope = parsed_authorization_request(&wire);
    let canonical = encode(
        &swm::build_swm_authorization_request(&envelope, EncodeContext::default())
            .expect("typed rebuild must canonicalize flags"),
    );
    let message = decode(&canonical);
    let mut remaining = message.raw_avps;
    while !remaining.is_empty() {
        let (tail, parsed) =
            opc_proto_diameter::RawAvp::decode(remaining, DecodeContext::default())
                .expect("rebuilt AVP must frame");
        if matches!(
            parsed.header.code,
            code if code == swm::AVP_AAR_FLAGS
                || code == swm::AVP_UE_LOCAL_IP_ADDRESS
                || code == swm::AVP_HIGH_PRIORITY_ACCESS_INFO
                || code == swm::AVP_DRMP
        ) {
            assert!(!parsed.header.flags.is_mandatory());
        }
        remaining = tail;
    }
}

#[test]
fn received_load_m_mismatch_is_tolerated_and_reemitted_canonically() {
    let load_children: Vec<u8> = [
        avp(swm::AVP_LOAD_TYPE, 0x00, &0_u32.to_be_bytes()),
        avp(swm::AVP_LOAD_VALUE, 0x00, &42_u64.to_be_bytes()),
        avp(swm::AVP_SOURCE_ID, 0x00, b"source-private-invalid"),
    ]
    .into_iter()
    .flatten()
    .collect();
    let mut avps = aaa_wire();
    let load = avp(swm::AVP_LOAD, 0x40, &load_children);
    let old_len = avps.len();
    avps.extend_from_slice(&load);
    let new_len = avps.len();
    avps[1..4].copy_from_slice(&(new_len as u32).to_be_bytes()[1..]);
    assert!(new_len > old_len);
    let answer = swm::parse_swm_authorization_answer(&decode(&avps), DecodeContext::default())
        .expect("understood Load must ignore the received M mismatch");
    let rebuilt = encode(
        &swm::build_swm_authorization_answer(
            &parsed_authorization_request(&aar_wire(0xc0)),
            &answer,
            EncodeContext::default(),
        )
        .expect("the encode boundary must normalize a received Load M mismatch"),
    );
    let rebuilt_message = decode(&rebuilt);
    let rebuilt_load = rebuilt_message
        .avps(DecodeContext::default())
        .find_map(|avp| {
            let avp = avp.expect("rebuilt AVP framing");
            (avp.header.code == swm::AVP_LOAD).then_some(avp)
        })
        .expect("rebuilt AAA must contain Load");
    assert!(!rebuilt_load.header.flags.is_mandatory());
}

#[test]
fn aaa_accepts_exactly_one_typed_experimental_result() {
    let grouped: Vec<u8> = [
        avp(
            base::AVP_VENDOR_ID,
            0x40,
            &VENDOR_ID_3GPP.get().to_be_bytes(),
        ),
        avp(
            base::AVP_EXPERIMENTAL_RESULT_CODE,
            0x40,
            &5_001_u32.to_be_bytes(),
        ),
    ]
    .into_iter()
    .flatten()
    .collect();
    let wire = message(
        265,
        0x40,
        HOP_AAR,
        END_AAR,
        vec![
            avp(base::AVP_SESSION_ID, 0x40, SESSION.as_bytes()),
            avp(
                base::AVP_AUTH_APPLICATION_ID,
                0x40,
                &swm::APPLICATION_ID.get().to_be_bytes(),
            ),
            avp(swm::AVP_AUTH_REQUEST_TYPE, 0x40, &2_u32.to_be_bytes()),
            avp(base::AVP_EXPERIMENTAL_RESULT, 0x40, &grouped),
            avp(base::AVP_ORIGIN_HOST, 0x40, b"aaa.private.invalid"),
            avp(base::AVP_ORIGIN_REALM, 0x40, b"private.invalid"),
            avp(base::AVP_USER_NAME, 0x40, USER.as_bytes()),
        ],
    );
    let answer = swm::parse_swm_authorization_answer(&decode(&wire), DecodeContext::default())
        .expect("experimental result AAA must parse");
    assert_eq!(
        answer.result,
        SwmDiameterResult::Experimental {
            vendor_id: VENDOR_ID_3GPP,
            code: 5_001,
        }
    );
}

#[test]
fn originated_aaa_rejects_experimental_protocol_error_class() {
    let request = parsed_authorization_request(&aar_wire(0xc0));
    let answer = swm::SwmAuthorizationAnswer::for_request(
        &request,
        SwmDiameterResult::Experimental {
            vendor_id: VENDOR_ID_3GPP,
            code: 3_001,
        },
        "aaa.private.invalid",
        "private.invalid",
    );
    swm::build_swm_authorization_answer(&request, &answer, EncodeContext::default())
        .expect_err("experimental 3xxx cannot satisfy RFC 6733 generic E-bit grammar");

    let answer = swm::SwmAuthorizationAnswer::for_request(
        &request,
        SwmDiameterResult::Experimental {
            vendor_id: VENDOR_ID_3GPP,
            code: 5_001,
        },
        "aaa.private.invalid",
        "private.invalid",
    );
    let built = swm::build_swm_authorization_answer(&request, &answer, EncodeContext::default())
        .expect("ordinary experimental application result remains encodable");
    assert!(!built.header.flags.is_error());
    let parsed =
        swm::parse_swm_authorization_answer(&decode(&encode(&built)), DecodeContext::default())
            .expect("originated experimental application result must self-parse");
    assert_eq!(parsed.result, answer.result);
}

#[test]
fn raa_origin_is_explicit_local_identity_not_request_destination() {
    let request = parsed_re_auth_request(&rar_wire(0xc0));
    let answer = SwmReAuthAnswer::for_request(
        &request,
        SwmReAuthResult::Success,
        "configured-local.private.invalid",
        "configured-realm.invalid",
    );
    assert_ne!(
        answer.origin_host.as_ref(),
        request.request().destination_host.as_ref()
    );
    assert_ne!(
        answer.origin_realm.as_ref(),
        request.request().destination_realm.as_ref()
    );

    let built = swm::build_swm_re_auth_answer(&request, &answer, EncodeContext::default())
        .expect("request-bound RAA accepts an explicitly configured local Origin");
    let parsed = swm::parse_swm_re_auth_answer(&decode(&encode(&built)), DecodeContext::default())
        .expect("explicit-origin RAA must parse");
    assert_eq!(
        parsed.origin_host.as_ref(),
        "configured-local.private.invalid"
    );
    assert_eq!(parsed.origin_realm.as_ref(), "configured-realm.invalid");
}

#[test]
fn code_collisions_are_vendor_aware_while_malformed_roles_and_headers_fail_closed() {
    let mut ietf_collision = aar_avps();
    let index = ietf_collision
        .iter()
        .position(|raw| {
            u32::from_be_bytes(raw[0..4].try_into().expect("fixed code"))
                == swm::AVP_AAR_FLAGS.get()
        })
        .expect("AAR-Flags fixture");
    ietf_collision[index] = avp(swm::AVP_AAR_FLAGS, 0x00, &1_u32.to_be_bytes());
    let wire = message(265, 0xc0, HOP_AAR, END_AAR, ietf_collision);
    let parsed = swm::parse_swm_authorization_request(&decode(&wire), DecodeContext::default())
        .expect("an unassigned IETF key must not alias the 3GPP AAR-Flags key");
    assert!(parsed.aar_flags.is_none());
    assert!(parsed
        .additional_avps
        .iter()
        .any(|avp| avp.code() == swm::AVP_AAR_FLAGS && avp.vendor_id().is_none()));

    let mut wrong_length = rar_avps();
    let index = wrong_length
        .iter()
        .position(|raw| {
            u32::from_be_bytes(raw[0..4].try_into().expect("fixed code"))
                == base::AVP_RE_AUTH_REQUEST_TYPE.get()
        })
        .expect("Re-Auth-Request-Type fixture");
    wrong_length[index] = avp(base::AVP_RE_AUTH_REQUEST_TYPE, 0x40, &[0, 0, 0]);
    let wire = message(258, 0xc0, HOP_RAR, END_RAR, wrong_length);
    assert!(swm::parse_swm_re_auth_request(&decode(&wire), DecodeContext::default()).is_err());

    let mut wrong_role = rar_avps();
    wrong_role.push(avp(base::AVP_RESULT_CODE, 0x40, &2_001_u32.to_be_bytes()));
    let wire = message(258, 0xc0, HOP_RAR, END_RAR, wrong_role);
    assert!(swm::parse_swm_re_auth_request(&decode(&wire), DecodeContext::default()).is_err());

    let wire = message(265, 0xc0, HOP_AAR, END_AAR, vec![]);
    assert!(swm::parse_swm_authorization_answer(&decode(&wire), DecodeContext::default()).is_err());

    let wire = message(
        258,
        0x60,
        HOP_RAR,
        END_RAR,
        vec![
            avp(base::AVP_SESSION_ID, 0x40, SESSION.as_bytes()),
            avp(base::AVP_RESULT_CODE, 0x40, &3_002_u32.to_be_bytes()),
            avp(base::AVP_ORIGIN_HOST, 0x40, b"epdg.private.invalid"),
            avp(base::AVP_ORIGIN_REALM, 0x40, b"private.invalid"),
            avp(base::AVP_USER_NAME, 0x40, USER.as_bytes()),
        ],
    );
    assert_eq!(
        swm::parse_swm_re_auth_answer(&decode(&wire), DecodeContext::default())
            .expect("generic protocol result must remain receive-side visible")
            .result,
        SwmReAuthResult::Other(3_002)
    );
}

#[test]
fn generic_e_bit_errors_accept_minimal_ccf_and_correlate_safely() {
    let re_auth_request = parsed_re_auth_request(&rar_wire(0xc0));
    let generic_raa = message(
        258,
        0x60,
        HOP_RAR,
        END_RAR,
        vec![
            avp(base::AVP_RESULT_CODE, 0x40, &3_002_u32.to_be_bytes()),
            avp(base::AVP_ORIGIN_HOST, 0x40, b"agent.private.invalid"),
            avp(base::AVP_ORIGIN_REALM, 0x40, b"agent.invalid"),
            proxy_info(),
        ],
    );
    let generic_raa = parsed_re_auth_answer(&decode(&generic_raa), CONNECTION_A);
    assert!(generic_raa.uses_generic_error_grammar());
    assert_eq!(generic_raa.answer().result, SwmReAuthResult::Other(3_002));
    assert!(generic_raa.answer().session_id.is_none());
    assert!(generic_raa.answer().user_name.is_none());
    re_auth_request
        .correlate_answer(generic_raa)
        .expect("agent error correlates by connection, transaction, P, and Proxy-Info");

    let authorization_request = parsed_authorization_request(&aar_wire(0xc0));
    let experimental_children: Vec<u8> = [
        avp(
            base::AVP_VENDOR_ID,
            0x40,
            &VENDOR_ID_3GPP.get().to_be_bytes(),
        ),
        avp(
            base::AVP_EXPERIMENTAL_RESULT_CODE,
            0x40,
            &5_005_u32.to_be_bytes(),
        ),
    ]
    .into_iter()
    .flatten()
    .collect();
    let generic_aaa = message(
        265,
        0x60,
        HOP_AAR,
        END_AAR,
        vec![
            avp(
                base::AVP_RESULT_CODE,
                0x40,
                &base::RESULT_CODE_DIAMETER_MISSING_AVP.to_be_bytes(),
            ),
            avp(base::AVP_ORIGIN_HOST, 0x40, b"agent.private.invalid"),
            avp(base::AVP_ORIGIN_REALM, 0x40, b"agent.invalid"),
            avp(base::AVP_EXPERIMENTAL_RESULT, 0x40, &experimental_children),
            proxy_info(),
        ],
    );
    let generic_aaa = parsed_authorization_answer(&decode(&generic_aaa), CONNECTION_A);
    assert!(generic_aaa.uses_generic_error_grammar());
    assert_eq!(
        generic_aaa.answer().result,
        SwmDiameterResult::Base(base::RESULT_CODE_DIAMETER_MISSING_AVP)
    );
    assert!(generic_aaa.answer().session_id.is_none());
    assert!(generic_aaa.answer().auth_request_type.is_none());
    assert!(generic_aaa.answer().user_name.is_none());
    assert_eq!(generic_aaa.answer().additional_avps.len(), 1);
    authorization_request
        .correlate_answer(generic_aaa)
        .expect("agent error is exempt only from logical-Origin correlation");

    let experimental_only = message(
        265,
        0x60,
        HOP_AAR,
        END_AAR,
        vec![
            avp(base::AVP_ORIGIN_HOST, 0x40, b"agent.private.invalid"),
            avp(base::AVP_ORIGIN_REALM, 0x40, b"agent.invalid"),
            avp(base::AVP_EXPERIMENTAL_RESULT, 0x40, &experimental_children),
        ],
    );
    assert!(
        swm::parse_swm_authorization_answer(&decode(&experimental_only), DecodeContext::default())
            .is_err(),
        "generic E-bit grammar requires base Result-Code"
    );
}

#[test]
fn ordinary_answers_apply_explicit_direct_or_routed_peer_policy() {
    let re_auth_request = parsed_re_auth_request(&rar_wire(0xc0));
    let wrong_host_raa = message(
        258,
        0x40,
        HOP_RAR,
        END_RAR,
        vec![
            avp(base::AVP_SESSION_ID, 0x40, SESSION.as_bytes()),
            avp(
                base::AVP_RESULT_CODE,
                0x40,
                &base::RESULT_CODE_DIAMETER_SUCCESS.to_be_bytes(),
            ),
            avp(base::AVP_ORIGIN_HOST, 0x40, b"evil.private.invalid"),
            avp(base::AVP_ORIGIN_REALM, 0x40, b"access.private.invalid"),
            avp(base::AVP_USER_NAME, 0x40, USER.as_bytes()),
            proxy_info(),
        ],
    );
    let wrong_host_raa = parsed_re_auth_answer(&decode(&wrong_host_raa), CONNECTION_A);
    assert_eq!(
        re_auth_request
            .clone()
            .correlate_answer(wrong_host_raa)
            .expect_err("direct RAA must satisfy the trusted logical-Origin policy"),
        swm::SwmAuthorizationCorrelationError::PeerIdentityMismatch
    );

    let wrong_realm_raa = message(
        258,
        0x40,
        HOP_RAR,
        END_RAR,
        vec![
            avp(base::AVP_SESSION_ID, 0x40, SESSION.as_bytes()),
            avp(
                base::AVP_RESULT_CODE,
                0x40,
                &base::RESULT_CODE_DIAMETER_SUCCESS.to_be_bytes(),
            ),
            avp(base::AVP_ORIGIN_HOST, 0x40, b"epdg.private.invalid"),
            avp(base::AVP_ORIGIN_REALM, 0x40, b"rogue.private.invalid"),
            avp(base::AVP_USER_NAME, 0x40, USER.as_bytes()),
            proxy_info(),
        ],
    );
    let wrong_realm_raa = parsed_re_auth_answer(&decode(&wrong_realm_raa), CONNECTION_A);
    assert_eq!(
        re_auth_request
            .correlate_answer(wrong_realm_raa)
            .expect_err("direct RAA realm must satisfy the trusted logical-Origin policy"),
        swm::SwmAuthorizationCorrelationError::PeerIdentityMismatch
    );

    let mut final_server_aaa = aaa_wire();
    let expected = b"dra.private.invalid";
    let replacement = b"aaa.private.invalid";
    assert_eq!(expected.len(), replacement.len());
    let position = final_server_aaa
        .windows(expected.len())
        .position(|window| window == expected)
        .expect("AAA Origin-Host must be present");
    final_server_aaa[position..position + replacement.len()].copy_from_slice(replacement);
    parsed_authorization_request(&aar_wire(0xc0))
        .correlate_answer(parsed_authorization_answer(
            &decode(&final_server_aaa),
            CONNECTION_A,
        ))
        .expect("routed AAR via DRA accepts the final AAA server Origin");

    let direct_request = parsed_authorization_request(&aar_wire(0xc0)).with_expected_answer_peer(
        SwmExpectedAnswerPeer::direct(CONNECTION_A, "dra.private.invalid", "aaa.private.invalid"),
    );
    assert_eq!(
        direct_request
            .correlate_answer(parsed_authorization_answer(
                &decode(&final_server_aaa),
                CONNECTION_A,
            ))
            .expect_err("direct AAR policy must reject a different final Origin-Host"),
        swm::SwmAuthorizationCorrelationError::PeerIdentityMismatch
    );

    let mut wrong_realm_aaa = aaa_wire();
    let expected = b"aaa.private.invalid";
    let replacement = b"bad.private.invalid";
    assert_eq!(expected.len(), replacement.len());
    let position = wrong_realm_aaa
        .windows(expected.len())
        .position(|window| window == expected)
        .expect("AAA Origin-Realm must be present");
    wrong_realm_aaa[position..position + replacement.len()].copy_from_slice(replacement);
    let realm_routed_request =
        parsed_authorization_request(&aar_wire(0xc0)).with_expected_answer_peer(
            SwmExpectedAnswerPeer::routed_in_realm(CONNECTION_A, "aaa.private.invalid"),
        );
    assert_eq!(
        realm_routed_request
            .correlate_answer(parsed_authorization_answer(
                &decode(&wrong_realm_aaa),
                CONNECTION_A,
            ))
            .expect_err("realm-routed AAR must reject an Origin outside its trusted realm"),
        swm::SwmAuthorizationCorrelationError::PeerIdentityMismatch
    );
}

#[test]
fn correlation_requires_binding_and_the_exact_connection_generation() {
    let unbound = swm::parse_swm_authorization_request_envelope(
        &decode(&aar_wire(0xc0)),
        DecodeContext::default(),
    )
    .expect("inbound AAR must parse without manufacturing transport evidence");
    assert!(
        swm::build_swm_authorization_request(&unbound, EncodeContext::default()).is_err(),
        "an unbound AAR cannot be dispatched as an outbound request"
    );
    assert_eq!(
        unbound
            .correlate_answer(parsed_authorization_answer(
                &decode(&aaa_wire()),
                CONNECTION_A,
            ))
            .expect_err("an unbound request must not correlate"),
        swm::SwmAuthorizationCorrelationError::PeerBindingMissing
    );

    let unbound_rar =
        swm::parse_swm_re_auth_request_envelope(&decode(&rar_wire(0xc0)), DecodeContext::default())
            .expect("inbound RAR must parse without manufacturing transport evidence");
    assert!(
        swm::build_swm_re_auth_request(&unbound_rar, EncodeContext::default()).is_err(),
        "an unbound RAR cannot be dispatched as an outbound request"
    );

    assert_eq!(
        parsed_authorization_request(&aar_wire(0xc0))
            .correlate_answer(parsed_authorization_answer(
                &decode(&aaa_wire()),
                CONNECTION_B,
            ))
            .expect_err("a new authenticated connection generation must not satisfy old state"),
        swm::SwmAuthorizationCorrelationError::PeerConnectionMismatch
    );

    let generic_error = message(
        265,
        0x60,
        HOP_AAR,
        END_AAR,
        vec![
            avp(base::AVP_RESULT_CODE, 0x40, &3_002_u32.to_be_bytes()),
            avp(base::AVP_ORIGIN_HOST, 0x40, b"agent.private.invalid"),
            avp(base::AVP_ORIGIN_REALM, 0x40, b"agent.invalid"),
            proxy_info(),
        ],
    );
    assert_eq!(
        parsed_authorization_request(&aar_wire(0xc0))
            .correlate_answer(parsed_authorization_answer(
                &decode(&generic_error),
                CONNECTION_B,
            ))
            .expect_err("generic E-bit errors skip Origin policy, not connection binding"),
        swm::SwmAuthorizationCorrelationError::PeerConnectionMismatch
    );
}

#[test]
fn additional_avp_count_is_bounded_independently_of_decode_context() {
    let mut avps = rar_avps();
    avps.retain(|raw| u32::from_be_bytes(raw[0..4].try_into().expect("fixed code")) != UNKNOWN);
    for code in 100_000..100_129 {
        avps.push(avp(AvpCode::new(code), 0x00, b"bounded-private-extension"));
    }
    let wire = message(258, 0xc0, HOP_RAR, END_RAR, avps);
    let error = swm::parse_swm_re_auth_request(
        &decode(&wire),
        DecodeContext {
            max_ies: 512,
            ..DecodeContext::default()
        },
    )
    .expect_err("129th additional AVP must exceed the typed bound");
    assert_eq!(error.code(), &DecodeErrorCode::IeCountExceeded);
}

