#[test]
fn missing_request_avps_have_typed_provenance_and_answers_reject_every_missing_field() {
    for missing in [
        base::AVP_SESSION_ID,
        base::AVP_ORIGIN_HOST,
        base::AVP_ORIGIN_REALM,
        base::AVP_DESTINATION_REALM,
        base::AVP_DESTINATION_HOST,
        base::AVP_AUTH_APPLICATION_ID,
        base::AVP_RE_AUTH_REQUEST_TYPE,
        base::AVP_USER_NAME,
    ] {
        let mut avps = rar_avps();
        avps.retain(|raw| {
            u32::from_be_bytes(raw[0..4].try_into().expect("fixed slice")) != missing.get()
        });
        let wire = message(258, 0xc0, HOP_RAR, END_RAR, avps);
        let error = swm::parse_swm_re_auth_request_with_provenance(
            &decode(&wire),
            DecodeContext::default(),
        )
        .expect_err("each missing RAR field must fail");
        let provenance = error.missing_avp().expect("RAR provenance");
        assert_eq!(provenance.avp_code(), missing);
        assert_eq!(provenance.command_code().get(), 258);
    }

    for missing in [
        base::AVP_SESSION_ID,
        base::AVP_AUTH_APPLICATION_ID,
        base::AVP_ORIGIN_HOST,
        base::AVP_ORIGIN_REALM,
        base::AVP_DESTINATION_REALM,
        swm::AVP_AUTH_REQUEST_TYPE,
        base::AVP_USER_NAME,
    ] {
        let mut avps = aar_avps();
        avps.retain(|raw| {
            u32::from_be_bytes(raw[0..4].try_into().expect("fixed slice")) != missing.get()
        });
        let wire = message(265, 0xc0, HOP_AAR, END_AAR, avps);
        let error = swm::parse_swm_authorization_request_with_provenance(
            &decode(&wire),
            DecodeContext::default(),
        )
        .expect_err("each missing AAR field must fail");
        let provenance = error.missing_avp().expect("AAR provenance");
        assert_eq!(provenance.avp_code(), missing);
        assert_eq!(provenance.command_code().get(), 265);
    }

    for missing in [
        base::AVP_SESSION_ID,
        base::AVP_RESULT_CODE,
        base::AVP_ORIGIN_HOST,
        base::AVP_ORIGIN_REALM,
        base::AVP_USER_NAME,
    ] {
        let mut avps = raa_avps();
        avps.retain(|raw| avp_code(raw) != missing.get());
        let wire = AuthorizationFixture::Raa.wire(avps);
        assert_bounded_rejection(
            AuthorizationFixture::Raa,
            "a missing mandatory AVP",
            &wire,
            DecodeContext::default(),
        );
    }

    for missing in [
        base::AVP_SESSION_ID,
        base::AVP_AUTH_APPLICATION_ID,
        swm::AVP_AUTH_REQUEST_TYPE,
        base::AVP_RESULT_CODE,
        base::AVP_ORIGIN_HOST,
        base::AVP_ORIGIN_REALM,
        base::AVP_USER_NAME,
    ] {
        let mut avps = aaa_avps();
        avps.retain(|raw| avp_code(raw) != missing.get());
        let wire = AuthorizationFixture::Aaa.wire(avps);
        assert_bounded_rejection(
            AuthorizationFixture::Aaa,
            "a missing mandatory AVP",
            &wire,
            DecodeContext::default(),
        );
    }
}

#[test]
fn every_authorization_command_rejects_duplicate_wrong_vendor_and_wrong_type_avps() {
    for fixture in AUTHORIZATION_FIXTURES {
        let mut duplicate = fixture.avps();
        let expected_offset = DIAMETER_HEADER_LEN + duplicate.iter().map(Vec::len).sum::<usize>();
        duplicate.push(avp(
            base::AVP_ORIGIN_HOST,
            0x40,
            b"duplicate.private.invalid",
        ));
        let wire = fixture.wire(duplicate);
        let error = assert_bounded_rejection(
            fixture,
            "a duplicated singleton",
            &wire,
            DecodeContext::default(),
        );
        assert_eq!(error.code(), &DecodeErrorCode::DuplicateIe);
        assert_eq!(error.offset(), expected_offset);

        let mut wrong_vendor = fixture.avps();
        replace_first_avp(
            &mut wrong_vendor,
            base::AVP_ORIGIN_HOST,
            vendor_avp(base::AVP_ORIGIN_HOST, 0x40, b"wrong-vendor.private.invalid"),
        );
        let wire = fixture.wire(wrong_vendor);
        assert_bounded_rejection(
            fixture,
            "a wrong-vendor core AVP",
            &wire,
            DecodeContext::default(),
        );

        let mut wrong_type = fixture.avps();
        replace_first_avp(
            &mut wrong_type,
            base::AVP_ORIGIN_HOST,
            avp(base::AVP_ORIGIN_HOST, 0x40, &[0xff]),
        );
        let wire = fixture.wire(wrong_type);
        assert_bounded_rejection(
            fixture,
            "a wrong-type core AVP value",
            &wire,
            DecodeContext::default(),
        );
    }
}

#[test]
fn every_authorization_command_rejects_wrong_role_and_wrong_application() {
    for fixture in AUTHORIZATION_FIXTURES {
        let mut wrong_role_header = fixture.wire(fixture.avps());
        wrong_role_header[4] ^= 0x80;
        assert_bounded_rejection(
            fixture,
            "the opposite command role",
            &wrong_role_header,
            DecodeContext::default(),
        );

        let mut wrong_role_avps = fixture.avps();
        if fixture.flags() & 0x80 != 0 {
            wrong_role_avps.push(avp(
                base::AVP_RESULT_CODE,
                0x40,
                &base::RESULT_CODE_DIAMETER_SUCCESS.to_be_bytes(),
            ));
        } else {
            wrong_role_avps.push(avp(
                base::AVP_DESTINATION_REALM,
                0x40,
                b"request-only.private.invalid",
            ));
        }
        let wire = fixture.wire(wrong_role_avps);
        assert_bounded_rejection(fixture, "a wrong-role AVP", &wire, DecodeContext::default());

        let mut wrong_application = fixture.wire(fixture.avps());
        let other_application = swm::APPLICATION_ID.get().saturating_add(1);
        wrong_application[8..12].copy_from_slice(&other_application.to_be_bytes());
        assert_bounded_rejection(
            fixture,
            "a wrong application id",
            &wrong_application,
            DecodeContext::default(),
        );
    }
}

#[test]
fn command_metadata_drives_supported_authorization_role_and_cardinality() {
    let dictionary = swm::dictionary();
    let command = |code, kind| {
        dictionary
            .find_command(swm::APPLICATION_ID, code, kind)
            .expect("authorization command definition must exist")
    };
    let rar = command(swm::COMMAND_RE_AUTH, CommandKind::Request);
    let raa = command(swm::COMMAND_RE_AUTH, CommandKind::Answer);
    let aar = command(swm::COMMAND_AA, CommandKind::Request);
    let aaa = command(swm::COMMAND_AA, CommandKind::Answer);

    assert!(rar.allows_multiple(AvpKey::ietf(base::AVP_CLASS)));
    assert!(raa.allows_multiple(AvpKey::ietf(base::AVP_CLASS)));
    assert!(raa.allows_multiple(AvpKey::ietf(base::AVP_FAILED_AVP)));
    assert!(raa.allows_multiple(AvpKey::ietf(swm::AVP_REPLY_MESSAGE)));
    assert!(aaa.allows_multiple(AvpKey::ietf(base::AVP_CLASS)));
    assert!(aaa.allows_multiple(AvpKey::ietf(base::AVP_FAILED_AVP)));
    assert!(aaa.allows_multiple(AvpKey::ietf(swm::AVP_REPLY_MESSAGE)));
    assert!(!aar.allows_multiple(AvpKey::ietf(base::AVP_CLASS)));
    assert!(aar
        .find_avp_rule(AvpKey::ietf(base::AVP_CLASS))
        .is_some_and(|rule| rule.cardinality().is_forbidden()));
    assert!(rar
        .find_avp_rule(AvpKey::ietf(swm::AVP_REPLY_MESSAGE))
        .is_some_and(|rule| !rule.cardinality().allows_multiple()));
    for command in [rar, raa, aaa] {
        assert!(command
            .find_avp_rule(AvpKey::ietf(base::AVP_RE_AUTH_REQUEST_TYPE))
            .is_some_and(
                |rule| !rule.cardinality().is_forbidden() && !rule.cardinality().allows_multiple()
            ));
    }
    assert!(aar
        .find_avp_rule(AvpKey::ietf(base::AVP_RE_AUTH_REQUEST_TYPE))
        .is_some_and(|rule| rule.cardinality().is_forbidden()));

    for command in [rar, raa, aar, aaa] {
        for key in [
            AvpKey::ietf(base::AVP_TERMINATION_CAUSE),
            AvpKey::ietf(base::AVP_AUTH_SESSION_STATE),
        ] {
            assert!(command
                .find_avp_rule(key)
                .is_some_and(|rule| rule.cardinality().is_forbidden()));
        }
    }

    for command in [rar, aar] {
        for key in [
            AvpKey::ietf(base::AVP_REDIRECT_HOST),
            AvpKey::ietf(base::AVP_REDIRECT_HOST_USAGE),
            AvpKey::ietf(base::AVP_REDIRECT_MAX_CACHE_TIME),
        ] {
            assert!(command
                .find_avp_rule(key)
                .is_some_and(|rule| rule.cardinality().is_forbidden()));
        }
    }
    for command in [raa, aaa] {
        assert!(command.allows_multiple(AvpKey::ietf(base::AVP_REDIRECT_HOST)));
        for key in [
            AvpKey::ietf(base::AVP_REDIRECT_HOST_USAGE),
            AvpKey::ietf(base::AVP_REDIRECT_MAX_CACHE_TIME),
        ] {
            assert!(command
                .find_avp_rule(key)
                .is_some_and(|rule| !rule.cardinality().allows_multiple()));
        }
    }
}

#[test]
fn answer_redirect_cardinality_is_visible_but_typed_context_stays_unsupported() {
    for fixture in [AuthorizationFixture::Raa, AuthorizationFixture::Aaa] {
        let mut avps = fixture.avps();
        replace_first_avp(
            &mut avps,
            base::AVP_RESULT_CODE,
            avp(base::AVP_RESULT_CODE, 0x40, &3_006_u32.to_be_bytes()),
        );
        avps.retain(|raw| avp_code(raw) != swm::AVP_APN_CONFIGURATION.get());
        let proxy_index = avps
            .iter()
            .position(|raw| avp_code(raw) == base::AVP_PROXY_INFO.get())
            .expect("authorization answer fixture has Proxy-Info");
        avps.insert(
            proxy_index,
            avp(
                base::AVP_REDIRECT_HOST,
                0x40,
                b"aaa://redirect-one.example.invalid",
            ),
        );
        avps.insert(
            proxy_index + 1,
            avp(
                base::AVP_REDIRECT_HOST,
                0x40,
                b"aaa://redirect-two.example.invalid;transport=sctp",
            ),
        );
        avps.insert(
            proxy_index + 2,
            avp(base::AVP_REDIRECT_HOST_USAGE, 0x40, &0_u32.to_be_bytes()),
        );
        avps.insert(
            proxy_index + 3,
            avp(
                base::AVP_REDIRECT_MAX_CACHE_TIME,
                0x40,
                &60_u32.to_be_bytes(),
            ),
        );
        let (hop, end) = fixture.identifiers();
        let wire = message(fixture.command(), 0x60, hop, end, avps.clone());
        let (tail, _) = Message::decode_with_dictionary(
            &wire,
            DecodeContext::conservative(),
            apps::APP_DICTIONARIES,
        )
        .expect("RFC 6733 Redirect-Host must remain explicitly repeatable");
        assert!(tail.is_empty());
        assert_bounded_rejection(
            fixture,
            "an unsupported typed redirect result context",
            &wire,
            DecodeContext::default(),
        );

        avps.insert(
            proxy_index + 4,
            avp(base::AVP_REDIRECT_HOST_USAGE, 0x40, &1_u32.to_be_bytes()),
        );
        let error = Message::decode_with_dictionary(
            &message(fixture.command(), 0x60, hop, end, avps),
            DecodeContext::conservative(),
            apps::APP_DICTIONARIES,
        )
        .expect_err("Redirect-Host-Usage must remain singleton");
        assert_eq!(error.code(), &DecodeErrorCode::DuplicateIe);
    }

    let rar = parsed_re_auth_request(&rar_wire(0xc0));
    let mut raa = swm::parse_swm_re_auth_answer(&decode(&raa_wire()), DecodeContext::default())
        .expect("RAA fixture must parse");
    raa.additional_avps.push(
        SwmAdditionalAvp::new(
            AvpHeader::ietf(base::AVP_REDIRECT_HOST, true),
            b"aaa://redirect.example.invalid".to_vec(),
            EncodeContext::default(),
        )
        .expect("valid Redirect-Host is structurally framed"),
    );
    swm::build_swm_re_auth_answer(&rar, &raa, EncodeContext::default())
        .expect_err("typed RAA builder must not originate unsupported redirect context");

    let aar = parsed_authorization_request(&aar_wire(0xc0));
    let mut aaa =
        swm::parse_swm_authorization_answer(&decode(&aaa_wire()), DecodeContext::default())
            .expect("AAA fixture must parse");
    aaa.additional_avps.push(
        SwmAdditionalAvp::new(
            AvpHeader::ietf(base::AVP_REDIRECT_HOST, true),
            b"aaa://redirect.example.invalid".to_vec(),
            EncodeContext::default(),
        )
        .expect("valid Redirect-Host is structurally framed"),
    );
    swm::build_swm_authorization_answer(&aar, &aaa, EncodeContext::default())
        .expect_err("typed AAA builder must not originate unsupported redirect context");
}

#[test]
fn repeated_failed_avps_survive_conservative_raa_and_aaa_rebuilds() {
    let failed = |host: &[u8]| {
        avp(
            base::AVP_FAILED_AVP,
            0x40,
            &avp(base::AVP_ORIGIN_HOST, 0x40, host),
        )
    };
    let ctx = DecodeContext {
        unknown_ie_policy: UnknownIePolicy::Preserve,
        ..DecodeContext::conservative()
    };

    let rar = parsed_re_auth_request(&rar_wire(0xc0));
    let mut raa_avps = raa_avps();
    let proxy = raa_avps.pop().expect("RAA fixture ends in Proxy-Info");
    raa_avps.extend([
        failed(b"first-failed.private.invalid"),
        failed(b"second-failed.private.invalid"),
        proxy,
    ]);
    let raa_wire = AuthorizationFixture::Raa.wire(raa_avps);
    let (tail, raa_message) =
        Message::decode_with_dictionary(&raa_wire, ctx, apps::APP_DICTIONARIES)
            .expect("RAA command metadata must permit repeated Failed-AVP");
    assert!(tail.is_empty());
    let raa = swm::parse_swm_re_auth_answer(&raa_message, ctx)
        .expect("typed RAA must preserve repeated Failed-AVP");
    assert_eq!(
        raa.additional_avps
            .iter()
            .filter(|avp| avp.code() == base::AVP_FAILED_AVP)
            .count(),
        2
    );
    let rebuilt = swm::build_swm_re_auth_answer(&rar, &raa, EncodeContext::default())
        .expect("repeated RAA Failed-AVP values must remain encodable");
    assert_eq!(encode(&rebuilt), raa_wire);

    let aar = parsed_authorization_request(&aar_wire(0xc0));
    let mut aaa_avps = aaa_avps();
    let proxy = aaa_avps.pop().expect("AAA fixture ends in Proxy-Info");
    aaa_avps.extend([
        failed(b"first-failed.private.invalid"),
        failed(b"second-failed.private.invalid"),
        proxy,
    ]);
    let aaa_wire = AuthorizationFixture::Aaa.wire(aaa_avps);
    let (tail, aaa_message) =
        Message::decode_with_dictionary(&aaa_wire, ctx, apps::APP_DICTIONARIES)
            .expect("AAA command metadata must permit repeated Failed-AVP");
    assert!(tail.is_empty());
    let aaa = swm::parse_swm_authorization_answer(&aaa_message, ctx)
        .expect("typed AAA must preserve repeated Failed-AVP");
    assert_eq!(
        aaa.additional_avps
            .iter()
            .filter(|avp| avp.code() == base::AVP_FAILED_AVP)
            .count(),
        2
    );
    let rebuilt = swm::build_swm_authorization_answer(&aar, &aaa, EncodeContext::default())
        .expect("repeated AAA Failed-AVP values must remain encodable");
    assert_eq!(encode(&rebuilt), aaa_wire);
}

#[test]
fn rfc4005_answer_extensions_use_command_specific_cardinality() {
    let augment = |mut avps: Vec<Vec<u8>>| {
        let result_index = avps
            .iter()
            .position(|raw| avp_code(raw) == base::AVP_RESULT_CODE.get())
            .expect("answer fixture contains Result-Code");
        avps.insert(
            result_index + 1,
            avp(base::AVP_RE_AUTH_REQUEST_TYPE, 0x40, &0_u32.to_be_bytes()),
        );
        let proxy = avps.pop().expect("answer fixture ends in Proxy-Info");
        avps.extend([
            avp(swm::AVP_REPLY_MESSAGE, 0x40, b"first-private-prompt"),
            avp(swm::AVP_REPLY_MESSAGE, 0x40, b"second-private-prompt"),
            proxy,
        ]);
        avps
    };
    let ctx = DecodeContext {
        unknown_ie_policy: UnknownIePolicy::Preserve,
        ..DecodeContext::conservative()
    };

    let raa_avps = augment(raa_avps());
    let raa_wire = AuthorizationFixture::Raa.wire(raa_avps.clone());
    let (tail, raa_message) =
        Message::decode_with_dictionary(&raa_wire, ctx, apps::APP_DICTIONARIES)
            .expect("RAA metadata must permit repeated Reply-Message");
    assert!(tail.is_empty());
    let raa = swm::parse_swm_re_auth_answer(&raa_message, ctx)
        .expect("typed RAA must retain RFC 4005 answer extensions");
    assert_eq!(
        raa.additional_avps
            .iter()
            .filter(|avp| avp.code() == swm::AVP_REPLY_MESSAGE)
            .count(),
        2
    );
    assert_eq!(
        raa.re_auth_request_type,
        Some(SwmReAuthRequestType::AuthorizeOnly)
    );
    let rebuilt = swm::build_swm_re_auth_answer(
        &parsed_re_auth_request(&rar_wire(0xc0)),
        &raa,
        EncodeContext::default(),
    )
    .expect("valid RAA extensions must survive typed rebuild");
    assert_eq!(encode(&rebuilt), raa_wire);

    let aaa_avps = augment(aaa_avps());
    let aaa_wire = AuthorizationFixture::Aaa.wire(aaa_avps.clone());
    let (tail, aaa_message) =
        Message::decode_with_dictionary(&aaa_wire, ctx, apps::APP_DICTIONARIES)
            .expect("AAA metadata must permit repeated Reply-Message");
    assert!(tail.is_empty());
    let aaa = swm::parse_swm_authorization_answer(&aaa_message, ctx)
        .expect("typed AAA must retain RFC 4005 answer extensions");
    assert_eq!(
        aaa.additional_avps
            .iter()
            .filter(|avp| avp.code() == swm::AVP_REPLY_MESSAGE)
            .count(),
        2
    );
    assert_eq!(
        aaa.re_auth_request_type,
        Some(SwmReAuthRequestType::AuthorizeOnly)
    );
    let rebuilt = swm::build_swm_authorization_answer(
        &parsed_authorization_request(&aar_wire(0xc0)),
        &aaa,
        EncodeContext::default(),
    )
    .expect("valid AAA extensions must survive typed rebuild");
    assert_eq!(encode(&rebuilt), aaa_wire);

    for (fixture, mut avps) in [
        (AuthorizationFixture::Raa, raa_avps),
        (AuthorizationFixture::Aaa, aaa_avps),
    ] {
        let proxy = avps.pop().expect("answer fixture ends in Proxy-Info");
        avps.push(avp(
            base::AVP_RE_AUTH_REQUEST_TYPE,
            0x40,
            &1_u32.to_be_bytes(),
        ));
        avps.push(proxy);
        let error =
            Message::decode_with_dictionary(&fixture.wire(avps), ctx, apps::APP_DICTIONARIES)
                .expect_err("Re-Auth-Request-Type must remain singleton in an answer");
        assert_eq!(error.code(), &DecodeErrorCode::DuplicateIe);
    }

    for fixture in [AuthorizationFixture::Raa, AuthorizationFixture::Aaa] {
        let mut avps = fixture.avps();
        avps.push(avp(
            base::AVP_RE_AUTH_REQUEST_TYPE,
            0x40,
            &2_u32.to_be_bytes(),
        ));
        let error = assert_bounded_rejection(
            fixture,
            "an unassigned Re-Auth-Request-Type",
            &fixture.wire(avps),
            DecodeContext::default(),
        );
        assert!(matches!(
            error.code(),
            DecodeErrorCode::InvalidEnumValue {
                field: "Re-Auth-Request-Type",
                value: 2
            }
        ));
    }
}

#[test]
fn authorization_timer_fixtures_round_trip_with_typed_values() {
    const AUTHORIZATION_LIFETIME: u32 = 600;
    const AUTH_GRACE_PERIOD: u32 = 60;
    const SESSION_TIMEOUT: u32 = 900;

    let mut raa_avps = raa_avps();
    let result_index = raa_avps
        .iter()
        .position(|raw| avp_code(raw) == base::AVP_RESULT_CODE.get())
        .expect("RAA fixture contains Result-Code");
    raa_avps.splice(
        result_index + 1..result_index + 1,
        [
            avp(base::AVP_RE_AUTH_REQUEST_TYPE, 0x40, &0_u32.to_be_bytes()),
            avp(
                base::AVP_AUTHORIZATION_LIFETIME,
                0x40,
                &AUTHORIZATION_LIFETIME.to_be_bytes(),
            ),
            avp(
                base::AVP_AUTH_GRACE_PERIOD,
                0x40,
                &AUTH_GRACE_PERIOD.to_be_bytes(),
            ),
        ],
    );
    let raa_wire = AuthorizationFixture::Raa.wire(raa_avps);
    let raa = swm::parse_swm_re_auth_answer(&decode(&raa_wire), DecodeContext::default())
        .expect("hand-authored RAA authorization timers must parse");
    assert_eq!(raa.authorization_lifetime, Some(AUTHORIZATION_LIFETIME));
    assert_eq!(raa.auth_grace_period, Some(AUTH_GRACE_PERIOD));
    assert_eq!(raa.session_id.as_deref().map(String::as_str), Some(SESSION));
    let rebuilt = swm::build_swm_re_auth_answer(
        &parsed_re_auth_request(&rar_wire(0xc0)),
        &raa,
        EncodeContext::default(),
    )
    .expect("typed RAA authorization timers must rebuild");
    assert_eq!(encode(&rebuilt), raa_wire);

    let aar_avps = vec![
        avp(base::AVP_SESSION_ID, 0x40, SESSION.as_bytes()),
        avp(
            base::AVP_AUTH_APPLICATION_ID,
            0x40,
            &swm::APPLICATION_ID.get().to_be_bytes(),
        ),
        avp(base::AVP_ORIGIN_HOST, 0x40, b"epdg.private.invalid"),
        avp(base::AVP_ORIGIN_REALM, 0x40, b"private.invalid"),
        avp(base::AVP_DESTINATION_REALM, 0x40, b"aaa.private.invalid"),
        avp(base::AVP_DESTINATION_HOST, 0x40, b"dra.private.invalid"),
        avp(swm::AVP_AUTH_REQUEST_TYPE, 0x40, &2_u32.to_be_bytes()),
        avp(base::AVP_USER_NAME, 0x40, USER.as_bytes()),
        avp(
            base::AVP_AUTHORIZATION_LIFETIME,
            0x40,
            &AUTHORIZATION_LIFETIME.to_be_bytes(),
        ),
        avp(
            base::AVP_AUTH_GRACE_PERIOD,
            0x40,
            &AUTH_GRACE_PERIOD.to_be_bytes(),
        ),
        proxy_info(),
    ];
    let aar_wire = AuthorizationFixture::Aar.wire(aar_avps);
    let aar = parsed_authorization_request(&aar_wire);
    assert_eq!(
        aar.request().authorization_lifetime,
        Some(AUTHORIZATION_LIFETIME)
    );
    assert_eq!(aar.request().auth_grace_period, Some(AUTH_GRACE_PERIOD));
    let rebuilt = swm::build_swm_authorization_request(&aar, EncodeContext::default())
        .expect("typed AAR authorization timers must rebuild");
    assert_eq!(encode(&rebuilt), aar_wire);

    let mut aaa_avps = aaa_avps();
    let result_index = aaa_avps
        .iter()
        .position(|raw| avp_code(raw) == base::AVP_RESULT_CODE.get())
        .expect("AAA fixture contains Result-Code");
    aaa_avps.splice(
        result_index + 1..result_index + 1,
        [
            avp(base::AVP_RE_AUTH_REQUEST_TYPE, 0x40, &0_u32.to_be_bytes()),
            avp(
                base::AVP_AUTHORIZATION_LIFETIME,
                0x40,
                &AUTHORIZATION_LIFETIME.to_be_bytes(),
            ),
            avp(
                base::AVP_AUTH_GRACE_PERIOD,
                0x40,
                &AUTH_GRACE_PERIOD.to_be_bytes(),
            ),
            avp(
                base::AVP_SESSION_TIMEOUT,
                0x40,
                &SESSION_TIMEOUT.to_be_bytes(),
            ),
        ],
    );
    let aaa_wire = AuthorizationFixture::Aaa.wire(aaa_avps);
    let aaa = swm::parse_swm_authorization_answer(&decode(&aaa_wire), DecodeContext::default())
        .expect("hand-authored AAA authorization timers must parse");
    assert_eq!(aaa.authorization_lifetime, Some(AUTHORIZATION_LIFETIME));
    assert_eq!(aaa.auth_grace_period, Some(AUTH_GRACE_PERIOD));
    assert_eq!(aaa.session_timeout, Some(SESSION_TIMEOUT));
    let rebuilt = swm::build_swm_authorization_answer(&aar, &aaa, EncodeContext::default())
        .expect("typed AAA authorization timers must rebuild");
    assert_eq!(encode(&rebuilt), aaa_wire);

    let debug = format!("{aaa:?}");
    for value in [AUTHORIZATION_LIFETIME, AUTH_GRACE_PERIOD, SESSION_TIMEOUT] {
        assert!(
            !debug.contains(&value.to_string()),
            "timer values must not appear in diagnostic output"
        );
    }
}

#[test]
fn authorization_timer_zero_absent_and_bounds_semantics_are_explicit() {
    let rar = parsed_re_auth_request(&rar_wire(0xc0));
    let mut raa = SwmReAuthAnswer::for_request(
        &rar,
        SwmReAuthResult::Success,
        Redacted::from("epdg.private.invalid".to_owned()),
        Redacted::from("access.private.invalid".to_owned()),
    );
    assert_eq!(raa.authorization_lifetime, None);
    assert_eq!(raa.auth_grace_period, None);
    raa.authorization_lifetime = Some(0);
    let wire = encode(
        &swm::build_swm_re_auth_answer(&rar, &raa, EncodeContext::default())
            .expect("zero Authorization-Lifetime does not require re-auth type"),
    );
    let parsed = swm::parse_swm_re_auth_answer(&decode(&wire), DecodeContext::default())
        .expect("zero Authorization-Lifetime must parse");
    assert_eq!(parsed.authorization_lifetime, Some(0));
    assert_eq!(parsed.re_auth_request_type, None);

    raa.authorization_lifetime = Some(u32::MAX);
    raa.re_auth_request_type = Some(SwmReAuthRequestType::AuthorizeOnly);
    let wire = encode(
        &swm::build_swm_re_auth_answer(&rar, &raa, EncodeContext::default())
            .expect("maximum Unsigned32 Authorization-Lifetime must remain representable"),
    );
    let parsed = swm::parse_swm_re_auth_answer(&decode(&wire), DecodeContext::default())
        .expect("maximum Unsigned32 Authorization-Lifetime must parse");
    assert_eq!(parsed.authorization_lifetime, Some(u32::MAX));

    let aar = parsed_authorization_request(&aar_wire(0xc0));
    let mut aaa = swm::SwmAuthorizationAnswer::for_request(
        &aar,
        SwmDiameterResult::Base(base::RESULT_CODE_DIAMETER_SUCCESS),
        Redacted::from("dra.private.invalid".to_owned()),
        Redacted::from("aaa.private.invalid".to_owned()),
    );
    assert_eq!(aaa.session_timeout, None);
    aaa.session_timeout = Some(0);
    let wire = encode(
        &swm::build_swm_authorization_answer(&aar, &aaa, EncodeContext::default())
            .expect("zero Session-Timeout represents an unlimited session"),
    );
    let parsed = swm::parse_swm_authorization_answer(&decode(&wire), DecodeContext::default())
        .expect("zero Session-Timeout must parse");
    assert_eq!(parsed.session_timeout, Some(0));

    let mut aaa_avps = aaa_avps();
    let result_index = aaa_avps
        .iter()
        .position(|raw| avp_code(raw) == base::AVP_RESULT_CODE.get())
        .expect("AAA fixture contains Result-Code");
    aaa_avps.splice(
        result_index + 1..result_index + 1,
        [
            avp(base::AVP_RE_AUTH_REQUEST_TYPE, 0x40, &0_u32.to_be_bytes()),
            avp(
                base::AVP_AUTHORIZATION_LIFETIME,
                0x40,
                &u32::MAX.to_be_bytes(),
            ),
            avp(base::AVP_SESSION_TIMEOUT, 0x40, &0_u32.to_be_bytes()),
        ],
    );
    let wire = AuthorizationFixture::Aaa.wire(aaa_avps);
    let parsed = swm::parse_swm_authorization_answer(&decode(&wire), DecodeContext::default())
        .expect("unlimited Session-Timeout must not shorten an authorization lifetime");
    assert_eq!(parsed.authorization_lifetime, Some(u32::MAX));
    assert_eq!(parsed.session_timeout, Some(0));
    let rebuilt = swm::build_swm_authorization_answer(&aar, &parsed, EncodeContext::default())
        .expect("unlimited Session-Timeout must remain encodable with a lifetime");
    assert_eq!(encode(&rebuilt), wire);
}

#[test]
fn authorization_timer_semantic_violations_fail_closed() {
    for fixture in [AuthorizationFixture::Raa, AuthorizationFixture::Aaa] {
        let mut avps = fixture.avps();
        avps.push(avp(
            base::AVP_AUTHORIZATION_LIFETIME,
            0x40,
            &1_u32.to_be_bytes(),
        ));
        let error = assert_bounded_rejection(
            fixture,
            "positive Authorization-Lifetime without Re-Auth-Request-Type",
            &fixture.wire(avps),
            DecodeContext::default(),
        );
        assert!(matches!(error.code(), DecodeErrorCode::Structural { .. }));
    }

    let mut aaa_avps = aaa_avps();
    aaa_avps.extend([
        avp(base::AVP_RE_AUTH_REQUEST_TYPE, 0x40, &0_u32.to_be_bytes()),
        avp(
            base::AVP_AUTHORIZATION_LIFETIME,
            0x40,
            &301_u32.to_be_bytes(),
        ),
        avp(base::AVP_SESSION_TIMEOUT, 0x40, &300_u32.to_be_bytes()),
    ]);
    let error = assert_bounded_rejection(
        AuthorizationFixture::Aaa,
        "Session-Timeout smaller than Authorization-Lifetime",
        &AuthorizationFixture::Aaa.wire(aaa_avps),
        DecodeContext::default(),
    );
    assert!(matches!(error.code(), DecodeErrorCode::Structural { .. }));

    let rar = parsed_re_auth_request(&rar_wire(0xc0));
    let mut raa = SwmReAuthAnswer::for_request(
        &rar,
        SwmReAuthResult::Success,
        Redacted::from("epdg.private.invalid".to_owned()),
        Redacted::from("access.private.invalid".to_owned()),
    );
    raa.authorization_lifetime = Some(1);
    let error = swm::build_swm_re_auth_answer(&rar, &raa, EncodeContext::default())
        .expect_err("builder must reject a positive lifetime without re-auth type");
    assert!(!error.to_string().contains('1'));

    let aar = parsed_authorization_request(&aar_wire(0xc0));
    let mut aaa = swm::SwmAuthorizationAnswer::for_request(
        &aar,
        SwmDiameterResult::Base(base::RESULT_CODE_DIAMETER_SUCCESS),
        Redacted::from("dra.private.invalid".to_owned()),
        Redacted::from("aaa.private.invalid".to_owned()),
    );
    aaa.re_auth_request_type = Some(SwmReAuthRequestType::AuthorizeOnly);
    aaa.authorization_lifetime = Some(301);
    aaa.session_timeout = Some(300);
    let error = swm::build_swm_authorization_answer(&aar, &aaa, EncodeContext::default())
        .expect_err("builder must reject an undersized Session-Timeout");
    assert!(!error.to_string().contains("300"));
    assert!(!error.to_string().contains("301"));
}

#[test]
fn aar_lifetime_hint_bounds_successful_aaa_build_and_correlation() {
    const HINT: u32 = 600;
    const LIFETIME_ERROR: &str =
        "success-class SWm AAA must honor the AAR Authorization-Lifetime ceiling";

    let mut request_avps = aar_avps();
    let proxy_index = request_avps
        .iter()
        .position(|raw| avp_code(raw) == base::AVP_PROXY_INFO.get())
        .expect("AAR fixture contains Proxy-Info");
    request_avps.insert(
        proxy_index,
        avp(base::AVP_AUTHORIZATION_LIFETIME, 0x40, &HINT.to_be_bytes()),
    );
    let request = parsed_authorization_request(&AuthorizationFixture::Aar.wire(request_avps));

    let success_results = [
        SwmDiameterResult::Base(base::RESULT_CODE_DIAMETER_SUCCESS),
        SwmDiameterResult::Base(2_002),
        SwmDiameterResult::Experimental {
            vendor_id: VENDOR_ID_3GPP,
            code: 2_002,
        },
    ];
    for result in success_results {
        let mut answer = swm::SwmAuthorizationAnswer::for_request(
            &request,
            result,
            Redacted::from("dra.private.invalid".to_owned()),
            Redacted::from("aaa.private.invalid".to_owned()),
        );
        let error =
            swm::build_swm_authorization_answer(&request, &answer, EncodeContext::default())
                .expect_err("every success-class AAA must return a lifetime after an AAR hint");
        assert_eq!(
            error.code(),
            &EncodeErrorCode::Structural {
                reason: LIFETIME_ERROR,
            }
        );
        assert!(!error.to_string().contains(&HINT.to_string()));

        answer.re_auth_request_type = Some(SwmReAuthRequestType::AuthorizeOnly);
        answer.authorization_lifetime = Some(HINT + 1);
        let error =
            swm::build_swm_authorization_answer(&request, &answer, EncodeContext::default())
                .expect_err("success-class AAA must not exceed the AAR lifetime ceiling");
        assert_eq!(
            error.code(),
            &EncodeErrorCode::Structural {
                reason: LIFETIME_ERROR,
            }
        );
        assert!(!error.to_string().contains(&(HINT + 1).to_string()));

        for accepted in [HINT, HINT - 1] {
            answer.authorization_lifetime = Some(accepted);
            let built =
                swm::build_swm_authorization_answer(&request, &answer, EncodeContext::default())
                    .expect("success-class AAA may equal or tighten the AAR lifetime ceiling");
            let received = parsed_authorization_answer(&decode(&encode(&built)), CONNECTION_A);
            request
                .clone()
                .correlate_answer(received)
                .expect("equal or shorter success-class AAA lifetime must correlate");
        }
    }

    let result_avp = |result: SwmDiameterResult| match result {
        SwmDiameterResult::Base(code) => avp(base::AVP_RESULT_CODE, 0x40, &code.to_be_bytes()),
        SwmDiameterResult::Experimental { vendor_id, code } => {
            let children: Vec<u8> = [
                avp(base::AVP_VENDOR_ID, 0x40, &vendor_id.get().to_be_bytes()),
                avp(
                    base::AVP_EXPERIMENTAL_RESULT_CODE,
                    0x40,
                    &code.to_be_bytes(),
                ),
            ]
            .into_iter()
            .flatten()
            .collect();
            avp(base::AVP_EXPERIMENTAL_RESULT, 0x40, &children)
        }
    };
    for result in success_results {
        for received_lifetime in [None, Some(HINT + 1)] {
            let mut answer_avps = aaa_avps();
            answer_avps.retain(|raw| avp_code(raw) != swm::AVP_APN_CONFIGURATION.get());
            let result_index = answer_avps
                .iter()
                .position(|raw| avp_code(raw) == base::AVP_RESULT_CODE.get())
                .expect("AAA fixture contains Result-Code");
            answer_avps[result_index] = result_avp(result);
            if let Some(lifetime) = received_lifetime {
                answer_avps.splice(
                    result_index + 1..result_index + 1,
                    [
                        avp(base::AVP_RE_AUTH_REQUEST_TYPE, 0x40, &0_u32.to_be_bytes()),
                        avp(
                            base::AVP_AUTHORIZATION_LIFETIME,
                            0x40,
                            &lifetime.to_be_bytes(),
                        ),
                    ],
                );
            }
            let wire = AuthorizationFixture::Aaa.wire(answer_avps);
            let received = parsed_authorization_answer(&decode(&wire), CONNECTION_A);
            let error = request
                .clone()
                .correlate_answer(received)
                .expect_err("received success-class AAA must honor the lifetime ceiling");
            assert_eq!(
                error,
                swm::SwmAuthorizationCorrelationError::AuthorizationLifetimeMismatch
            );
            assert_eq!(error.as_str(), "swm_authorization_lifetime_mismatch");
            assert_eq!(error.to_string(), "swm_authorization_lifetime_mismatch");
        }
    }

    let failed_answer = swm::SwmAuthorizationAnswer::for_request(
        &request,
        SwmDiameterResult::Experimental {
            vendor_id: VENDOR_ID_3GPP,
            code: 5_001,
        },
        Redacted::from("dra.private.invalid".to_owned()),
        Redacted::from("aaa.private.invalid".to_owned()),
    );
    let built =
        swm::build_swm_authorization_answer(&request, &failed_answer, EncodeContext::default())
            .expect("an unsuccessful AAA need not grant an authorization lifetime");
    let received = parsed_authorization_answer(&decode(&encode(&built)), CONNECTION_A);
    request
        .correlate_answer(received)
        .expect("the request lifetime ceiling applies only to successful AAA");
}

#[test]
fn authorization_timer_cardinality_roles_and_types_fail_closed() {
    for (fixture, code) in [
        (AuthorizationFixture::Raa, base::AVP_AUTHORIZATION_LIFETIME),
        (AuthorizationFixture::Raa, base::AVP_AUTH_GRACE_PERIOD),
        (AuthorizationFixture::Aar, base::AVP_AUTHORIZATION_LIFETIME),
        (AuthorizationFixture::Aar, base::AVP_AUTH_GRACE_PERIOD),
        (AuthorizationFixture::Aaa, base::AVP_AUTHORIZATION_LIFETIME),
        (AuthorizationFixture::Aaa, base::AVP_AUTH_GRACE_PERIOD),
        (AuthorizationFixture::Aaa, base::AVP_SESSION_TIMEOUT),
    ] {
        let mut avps = fixture.avps();
        avps.extend([
            avp(code, 0x40, &0_u32.to_be_bytes()),
            avp(code, 0x40, &0_u32.to_be_bytes()),
        ]);
        let error = assert_bounded_rejection(
            fixture,
            "a duplicate authorization timer",
            &fixture.wire(avps),
            DecodeContext::default(),
        );
        assert_eq!(error.code(), &DecodeErrorCode::DuplicateIe);
    }

    for (fixture, code) in [
        (AuthorizationFixture::Rar, base::AVP_AUTHORIZATION_LIFETIME),
        (AuthorizationFixture::Rar, base::AVP_AUTH_GRACE_PERIOD),
        (AuthorizationFixture::Rar, base::AVP_SESSION_TIMEOUT),
        (AuthorizationFixture::Raa, base::AVP_SESSION_TIMEOUT),
        (AuthorizationFixture::Aar, base::AVP_SESSION_TIMEOUT),
    ] {
        let mut avps = fixture.avps();
        avps.push(avp(code, 0x40, &0_u32.to_be_bytes()));
        let error = assert_bounded_rejection(
            fixture,
            "an authorization timer in the wrong command role",
            &fixture.wire(avps),
            DecodeContext::default(),
        );
        assert!(matches!(error.code(), DecodeErrorCode::Structural { .. }));
    }

    for (fixture, code) in [
        (AuthorizationFixture::Raa, base::AVP_AUTHORIZATION_LIFETIME),
        (AuthorizationFixture::Raa, base::AVP_AUTH_GRACE_PERIOD),
        (AuthorizationFixture::Aar, base::AVP_AUTHORIZATION_LIFETIME),
        (AuthorizationFixture::Aar, base::AVP_AUTH_GRACE_PERIOD),
        (AuthorizationFixture::Aaa, base::AVP_SESSION_TIMEOUT),
    ] {
        let mut avps = fixture.avps();
        avps.push(avp(code, 0x40, &[0, 0, 1]));
        let error = assert_bounded_rejection(
            fixture,
            "a non-Unsigned32 authorization timer",
            &fixture.wire(avps),
            DecodeContext::default(),
        );
        assert!(matches!(
            error.code(),
            DecodeErrorCode::InvalidLength { .. }
        ));
    }
}

#[test]
fn role_forbidden_additional_avps_fail_on_decode_and_encode() {
    for fixture in AUTHORIZATION_FIXTURES {
        for (code, value) in [
            (base::AVP_TERMINATION_CAUSE, 1_u32.to_be_bytes()),
            (base::AVP_AUTH_SESSION_STATE, 0_u32.to_be_bytes()),
        ] {
            let mut avps = fixture.avps();
            avps.push(avp(code, 0x40, &value));
            let wire = fixture.wire(avps);
            assert_bounded_rejection(
                fixture,
                "a command-forbidden lifecycle AVP",
                &wire,
                DecodeContext::default(),
            );
        }
    }

    let mut aar_with_class = aar_avps();
    aar_with_class.push(avp(base::AVP_CLASS, 0x40, b"invalid-aar-class"));
    assert_bounded_rejection(
        AuthorizationFixture::Aar,
        "RFC 4005 AAR Class occurrence zero",
        &AuthorizationFixture::Aar.wire(aar_with_class),
        DecodeContext::default(),
    );

    for fixture in [AuthorizationFixture::Rar, AuthorizationFixture::Aar] {
        for code in [
            base::AVP_ERROR_MESSAGE,
            base::AVP_ERROR_REPORTING_HOST,
            base::AVP_FAILED_AVP,
        ] {
            let mut avps = fixture.avps();
            let value = if code == base::AVP_FAILED_AVP {
                avp(base::AVP_ORIGIN_HOST, 0x40, b"failed.private.invalid")
            } else {
                b"answer-only.private.invalid".to_vec()
            };
            avps.push(avp(code, 0x40, &value));
            assert_bounded_rejection(
                fixture,
                "an answer-only AVP in a request",
                &fixture.wire(avps),
                DecodeContext::default(),
            );
        }
        for (code, value) in [
            (
                base::AVP_REDIRECT_HOST,
                b"aaa://redirect.example.invalid".to_vec(),
            ),
            (base::AVP_REDIRECT_HOST_USAGE, 0_u32.to_be_bytes().to_vec()),
            (
                base::AVP_REDIRECT_MAX_CACHE_TIME,
                60_u32.to_be_bytes().to_vec(),
            ),
        ] {
            let mut avps = fixture.avps();
            avps.push(avp(code, 0x40, &value));
            assert_bounded_rejection(
                fixture,
                "an answer-only redirect AVP in a request",
                &fixture.wire(avps),
                DecodeContext::default(),
            );
        }
    }

    let request = parsed_authorization_request(&aar_wire(0xc0));
    let mut answer =
        swm::parse_swm_authorization_answer(&decode(&aaa_wire()), DecodeContext::default())
            .expect("AAA fixture must parse");
    answer.additional_avps.push(
        SwmAdditionalAvp::new(
            AvpHeader::ietf(base::AVP_TERMINATION_CAUSE, true),
            1_u32.to_be_bytes().to_vec(),
            EncodeContext::default(),
        )
        .expect("Termination-Cause test AVP must frame"),
    );
    swm::build_swm_authorization_answer(&request, &answer, EncodeContext::default())
        .expect_err("AAA encode must reject command-forbidden Termination-Cause");
}

#[test]
fn every_authorization_command_rejects_malformed_grouped_and_unknown_mandatory_avps() {
    for fixture in AUTHORIZATION_FIXTURES {
        let mut malformed_grouped = fixture.avps();
        let grouped_offset = DIAMETER_HEADER_LEN
            + malformed_grouped
                .iter()
                .take_while(|raw| avp_code(raw) != base::AVP_PROXY_INFO.get())
                .map(Vec::len)
                .sum::<usize>();
        replace_first_avp(
            &mut malformed_grouped,
            base::AVP_PROXY_INFO,
            avp(base::AVP_PROXY_INFO, 0x40, &[0, 0, 0]),
        );
        let wire = fixture.wire(malformed_grouped);
        let error = assert_bounded_rejection(
            fixture,
            "a malformed grouped AVP",
            &wire,
            DecodeContext::default(),
        );
        assert!(error.offset() >= grouped_offset);

        let mut unknown_mandatory = fixture.avps();
        let unknown_offset =
            DIAMETER_HEADER_LEN + unknown_mandatory.iter().map(Vec::len).sum::<usize>();
        unknown_mandatory.push(avp(
            AvpCode::new(UNKNOWN + 99),
            0x40,
            b"unknown-mandatory-private-value",
        ));
        let wire = fixture.wire(unknown_mandatory);
        let error = assert_bounded_rejection(
            fixture,
            "an unknown mandatory AVP",
            &wire,
            DecodeContext::default(),
        );
        assert_eq!(error.code(), &DecodeErrorCode::UnknownCriticalIe);
        assert_eq!(error.offset(), unknown_offset);
    }
}

#[test]
fn every_authorization_command_enforces_message_and_typed_collection_bounds() {
    for fixture in AUTHORIZATION_FIXTURES {
        let wire = fixture.wire(fixture.avps());
        let decode_error = Message::decode(
            &wire,
            DecodeContext {
                max_message_len: wire.len().saturating_sub(1),
                ..DecodeContext::default()
            },
        )
        .expect_err("message framing must enforce the configured byte bound");
        assert_eq!(decode_error.code(), &DecodeErrorCode::MessageLengthExceeded);
        assert!(decode_error.offset() <= wire.len());

        let mut oversized = fixture.avps();
        oversized.retain(|raw| {
            let code = avp_code(raw);
            code != UNKNOWN && code != UNKNOWN + 1
        });
        for code in 200_000..200_129 {
            oversized.push(avp(AvpCode::new(code), 0x00, b"bounded-private-extension"));
        }
        let wire = fixture.wire(oversized);
        let error = assert_bounded_rejection(
            fixture,
            "an oversized typed extension collection",
            &wire,
            DecodeContext {
                max_ies: 512,
                ..DecodeContext::default()
            },
        );
        assert_eq!(error.code(), &DecodeErrorCode::IeCountExceeded);
    }
}

#[test]
fn unknown_policy_and_duplicate_singletons_fail_closed() {
    let wire = rar_wire(0xc0);
    let preserved = swm::parse_swm_re_auth_request(
        &decode(&wire),
        DecodeContext {
            unknown_ie_policy: UnknownIePolicy::Preserve,
            ..DecodeContext::default()
        },
    )
    .expect("optional extension must be preserved");
    assert_eq!(preserved.additional_avps.len(), 1);
    let dropped = swm::parse_swm_re_auth_request(
        &decode(&wire),
        DecodeContext {
            unknown_ie_policy: UnknownIePolicy::Drop,
            ..DecodeContext::default()
        },
    )
    .expect("optional extension may be dropped");
    assert!(dropped.additional_avps.is_empty());
    let rejected = swm::parse_swm_re_auth_request(
        &decode(&wire),
        DecodeContext {
            unknown_ie_policy: UnknownIePolicy::Reject,
            ..DecodeContext::default()
        },
    )
    .expect_err("reject policy must reject unknown extension");
    assert_eq!(rejected.code(), &DecodeErrorCode::UnknownCriticalIe);

    let mut avps = rar_avps();
    avps.push(avp(base::AVP_SESSION_ID, 0x40, SESSION.as_bytes()));
    let duplicate = message(258, 0xc0, HOP_RAR, END_RAR, avps);
    let error = swm::parse_swm_re_auth_request(&decode(&duplicate), DecodeContext::default())
        .expect_err("duplicate Session-Id must fail");
    assert_eq!(error.code(), &DecodeErrorCode::DuplicateIe);
}

#[test]
fn vendor_specific_extension_code_collisions_round_trip_by_exact_key() {
    let original = typed_rar_envelope();
    let transaction = original.transaction();
    let mut request = original.request().clone();
    request.additional_avps.push(
        SwmAdditionalAvp::new(
            AvpHeader::vendor(base::AVP_SESSION_ID, VENDOR_ID_3GPP, false),
            b"private-vendor-extension".to_vec(),
            EncodeContext::default(),
        )
        .expect("M-clear vendor extension must frame"),
    );
    let envelope = SwmReAuthRequestEnvelope::for_outbound(
        request,
        transaction,
        expected_re_auth_peer(CONNECTION_A),
    );
    let built = swm::build_swm_re_auth_request(&envelope, EncodeContext::default())
        .expect("vendor-specific numeric collision must encode");
    let wire = encode(&built);
    let parsed = swm::parse_swm_re_auth_request(
        &decode(&wire),
        DecodeContext {
            unknown_ie_policy: UnknownIePolicy::Preserve,
            ..DecodeContext::default()
        },
    )
    .expect("vendor-specific numeric collision must not shadow the IETF key");
    assert!(parsed.additional_avps.iter().any(|avp| {
        avp.code() == base::AVP_SESSION_ID && avp.vendor_id() == Some(VENDOR_ID_3GPP)
    }));
}

