#[test]
fn update_sequence_caches_answer_and_rfc_compliant_aar_retry() {
    let rar = typed_rar_envelope();
    let raa = SwmReAuthAnswer::for_request(
        &rar,
        SwmReAuthResult::Success,
        Redacted::from("epdg.private.invalid".to_owned()),
        Redacted::from("access.private.invalid".to_owned()),
    );
    let accepted = SwmAcceptedAuthorizationUpdate::accept(rar, raa, EncodeContext::default())
        .expect("successful RAA must commit");
    assert_eq!(
        encode(&accepted.replay_re_auth_answer()),
        encode(&accepted.replay_re_auth_answer())
    );
    let mut pending = accepted
        .begin_authorization(
            SwmAuthorizationRequest {
                session_id: Redacted::from(SESSION.to_owned()),
                origin_host: Redacted::from("epdg.private.invalid".to_owned()),
                origin_realm: Redacted::from("private.invalid".to_owned()),
                destination_realm: Redacted::from("aaa.private.invalid".to_owned()),
                destination_host: None,
                user_name: Redacted::from(USER.to_owned()),
                auth_request_type: AuthRequestType::AuthorizeOnly,
                authorization_lifetime: None,
                auth_grace_period: None,
                aar_flags: None,
                ue_local_ip_address: None,
                high_priority_access_info: None,
                drmp: None,
                route_records: Vec::new(),
                additional_avps: Vec::new(),
            },
            SwmDiameterTransaction::new(HOP_AAR, END_AAR),
            expected_authorization_peer(CONNECTION_A),
            EncodeContext::default(),
        )
        .expect("matching AAR must commit");
    let initial = encode(&pending.initial_authorization_request());
    let retry = encode(&pending.retransmit_authorization_request());
    assert_eq!(initial[4] & 0x10, 0);
    assert_eq!(retry[4] & 0x10, 0);
    assert_eq!(initial, retry);
    assert_eq!(
        retry,
        encode(&pending.retransmit_authorization_request()),
        "ordinary cached retries must remain byte-identical"
    );
    pending
        .mark_for_failover_retransmission(
            HOP_FAILOVER,
            expected_authorization_peer(CONNECTION_B),
            EncodeContext::default(),
        )
        .expect("queued AAR may transition after link failover");
    let failover_retry = encode(&pending.retransmit_authorization_request());
    assert_eq!(failover_retry[4] & 0x10, 0x10);
    assert_eq!(&failover_retry[5..12], &initial[5..12]);
    assert_eq!(&failover_retry[12..16], &HOP_FAILOVER.to_be_bytes());
    assert_eq!(&failover_retry[16..], &initial[16..]);
    let aaa = message(
        265,
        0x40,
        HOP_FAILOVER,
        END_AAR,
        vec![
            avp(base::AVP_SESSION_ID, 0x40, SESSION.as_bytes()),
            avp(
                base::AVP_AUTH_APPLICATION_ID,
                0x40,
                &swm::APPLICATION_ID.get().to_be_bytes(),
            ),
            avp(swm::AVP_AUTH_REQUEST_TYPE, 0x40, &2_u32.to_be_bytes()),
            avp(
                base::AVP_RESULT_CODE,
                0x40,
                &base::RESULT_CODE_DIAMETER_SUCCESS.to_be_bytes(),
            ),
            avp(base::AVP_ORIGIN_HOST, 0x40, b"aaa.private.invalid"),
            avp(base::AVP_ORIGIN_REALM, 0x40, b"aaa.private.invalid"),
            avp(base::AVP_USER_NAME, 0x40, USER.as_bytes()),
        ],
    );
    let aaa = parsed_authorization_answer(&decode(&aaa), CONNECTION_B);
    let completed = pending.complete(aaa).expect("terminal AAA must correlate");
    assert_eq!(
        completed.authorization().answer().result,
        SwmDiameterResult::Base(base::RESULT_CODE_DIAMETER_SUCCESS)
    );
}

#[test]
fn update_sequence_rejects_non_successful_raa_and_identity_drift() {
    let rar = typed_rar_envelope();
    let rejected = SwmReAuthAnswer::for_request(
        &rar,
        SwmReAuthResult::UnableToComply,
        Redacted::from("epdg.private.invalid".to_owned()),
        Redacted::from("access.private.invalid".to_owned()),
    );
    assert!(
        SwmAcceptedAuthorizationUpdate::accept(rar, rejected, EncodeContext::default(),).is_err()
    );

    let rar = typed_rar_envelope();
    let accepted_answer = SwmReAuthAnswer::for_request(
        &rar,
        SwmReAuthResult::Success,
        Redacted::from("epdg.private.invalid".to_owned()),
        Redacted::from("access.private.invalid".to_owned()),
    );
    let accepted =
        SwmAcceptedAuthorizationUpdate::accept(rar, accepted_answer, EncodeContext::default())
            .expect("successful RAA must commit");
    let drifted = SwmAuthorizationRequest {
        session_id: Redacted::from("different-session".to_owned()),
        origin_host: Redacted::from("epdg.private.invalid".to_owned()),
        origin_realm: Redacted::from("private.invalid".to_owned()),
        destination_realm: Redacted::from("aaa.private.invalid".to_owned()),
        destination_host: None,
        user_name: Redacted::from(USER.to_owned()),
        auth_request_type: AuthRequestType::AuthorizeOnly,
        authorization_lifetime: None,
        auth_grace_period: None,
        aar_flags: None,
        ue_local_ip_address: None,
        high_priority_access_info: None,
        drmp: None,
        route_records: Vec::new(),
        additional_avps: Vec::new(),
    };
    assert!(accepted
        .begin_authorization(
            drifted,
            SwmDiameterTransaction::new(HOP_AAR, END_AAR),
            expected_authorization_peer(CONNECTION_A),
            EncodeContext::default(),
        )
        .is_err());
}

#[test]
fn debug_output_redacts_session_user_and_ip() {
    let request =
        swm::parse_swm_authorization_request(&decode(&aar_wire(0xc0)), DecodeContext::default())
            .expect("AAR must parse");
    let debug = format!("{request:?}");
    assert!(!debug.contains(SESSION));
    assert!(!debug.contains(USER));
    assert!(!debug.contains("198.51.100.10"));

    let envelope = parsed_authorization_request(&aar_wire(0xc0));
    let envelope_debug = format!("{envelope:?}");
    assert!(!envelope_debug.contains(SESSION));
    assert!(!envelope_debug.contains(USER));
    assert!(!envelope_debug.contains("dra.private.invalid"));
}
